# nfrs/error_classifier.py
from enum import Enum

class RequestOutcome(str, Enum):
    SUCCESS = "success"
    CLIENT_ERROR = "client_error"       # 4xx from caller — not charged to SLO
    INTEGRATION_ERROR = "integration_error"  # 5xx — charged to reliability SLO
    TIMEOUT = "timeout"                 # request killed at P99 limit — charged
    DEGRADED_RESPONSE = "degraded"      # success but fallback path used — tracked separately

def classify_outcome(
    http_status: int,
    response_is_error_payload: bool,
    timed_out: bool,
    used_fallback: bool,
) -> RequestOutcome:
    if timed_out:
        return RequestOutcome.TIMEOUT
    if http_status >= 500:
        return RequestOutcome.INTEGRATION_ERROR
    if http_status >= 400:
        return RequestOutcome.CLIENT_ERROR
    if response_is_error_payload:
        return RequestOutcome.INTEGRATION_ERROR
    if used_fallback:
        return RequestOutcome.DEGRADED_RESPONSE
    return RequestOutcome.SUCCESS

def is_slo_error(outcome: RequestOutcome) -> bool:
    return outcome in (RequestOutcome.INTEGRATION_ERROR, RequestOutcome.TIMEOUT)

