import time
from dataclasses import dataclass

@dataclass
class KnowledgeBaseStatus:
    most_recent_doc_timestamp: float   # Unix timestamp of newest indexed doc
    last_sync_run_timestamp: float     # When the sync job last completed
    last_sync_duration_seconds: float

    def freshness_hours(self) -> float:
        return (time.time() - self.most_recent_doc_timestamp) / 3600

    def hours_since_sync(self) -> float:
        return (time.time() - self.last_sync_run_timestamp) / 3600

def check_freshness_nfr(
    status: KnowledgeBaseStatus,
    staleness_slo_hours: float,
    expected_sync_duration_seconds: float,
) -> list[str]:
    violations = []
    if status.freshness_hours() > staleness_slo_hours:
        violations.append(
            f"KB freshness {status.freshness_hours():.1f}h exceeds SLO {staleness_slo_hours}h"
        )
    if status.last_sync_duration_seconds > 2 * expected_sync_duration_seconds:
        violations.append(
            f"Sync duration {status.last_sync_duration_seconds:.0f}s exceeds 2× expected "
            f"({expected_sync_duration_seconds:.0f}s)"
        )
    return violations

# nfrs/rto_tracker.py
import time
from dataclasses import dataclass, field
from typing import Optional

@dataclass
class IncidentTracker:
    severity: str
    declared_at: float = field(default_factory=time.monotonic)
    resolved_at: Optional[float] = None

    RTO_SECONDS = {
        "P1": 2 * 3600,    # 2 hours
        "P2": 8 * 3600,    # 8 hours
        "P3": 24 * 3600,   # 1 business day
        "P4": 5 * 24 * 3600,  # 1 week
    }

    @property
    def elapsed_seconds(self) -> float:
        end = self.resolved_at or time.monotonic()
        return end - self.declared_at

    @property
    def rto_seconds(self) -> int:
        return self.RTO_SECONDS[self.severity]

    @property
    def within_rto(self) -> bool:
        if self.resolved_at is None:
            return self.elapsed_seconds < self.rto_seconds
        return (self.resolved_at - self.declared_at) <= self.rto_seconds

    def resolve(self) -> None:
        self.resolved_at = time.monotonic()
        if not self.within_rto:
            print(
                f"RTO breach: {self.severity} resolved in "
                f"{self.elapsed_seconds/3600:.1f}h, RTO was "
                f"{self.rto_seconds/3600:.1f}h"
            )

# nfrs/error_budget.py
from dataclasses import dataclass

@dataclass
class ErrorBudget:
    availability_slo: float    # e.g. 0.995 for 99.5%
    window_days: int = 30

    @property
    def error_budget_minutes(self) -> float:
        # Total minutes in the measurement window
        total_minutes = self.window_days * 24 * 60
        return total_minutes * (1 - self.availability_slo)

    def budget_remaining(self, downtime_minutes: float) -> float:
        return self.error_budget_minutes - downtime_minutes

    def burn_rate(self, downtime_minutes: float, elapsed_minutes: float) -> float:
        # Burn rate > 1.0 means budget will be exhausted before window ends
        if elapsed_minutes == 0:
            return 0.0
        actual_error_rate = downtime_minutes / elapsed_minutes
        allowed_error_rate = 1 - self.availability_slo
        return actual_error_rate / allowed_error_rate

    def alert_needed(self, downtime_minutes: float, elapsed_minutes: float) -> bool:
        # Alert if 1-hour burn rate implies budget exhaustion in < 2 hours
        burn = self.burn_rate(downtime_minutes, elapsed_minutes)
        return burn > 14.4  # 14.4x = exhausts monthly budget in ~2 hours

# Example: 99.5% SLO, 30-day window
budget = ErrorBudget(availability_slo=0.995)
print(f"Error budget: {budget.error_budget_minutes:.1f} minutes")  # 216 minutes

# After 5 days, 60 minutes of downtime observed
burn = budget.burn_rate(downtime_minutes=60, elapsed_minutes=5*24*60)
print(f"Burn rate: {burn:.1f}x")  # 2.5x — budget will be exhausted before month end
